ee:message.ee:set-payload:
%dw 2.0
output application/json
var defaultError = {
      status: 500,
      reason: "Internal Server Error",
      message: vars.serverError default "There is a server issue"
   }
var valid = if ( (!isEmpty(vars.errorDef.status)) and (!isEmpty(vars.errorDef.reason)) ) true else false
var status = if (valid) vars.errorDef.status else defaultError.status
var reason = if (valid) vars.errorDef.reason else defaultError.reason
var message = if (valid) vars.errorDef.message else defaultError.message
---
{
    error: {
    	status: status as Number,
	    reason: reason as String,
	    message: message default ""
    }
}
